SELECT * FROM t_transaction
WHERE (requester_id = #{userId} OR owner_id = #{userId})

    AND trans_status = #{status}

ORDER BY create_time DESC
LIMIT #{offset}, #{pageSize}

SELECT COUNT(*) FROM t_transaction
WHERE (requester_id = #{userId} OR owner_id = #{userId})

    AND trans_status = #{status}

SELECT t.* FROM t_transaction t LEFT JOIN t_textbook b ON t.textbook_id = b.id
AND t.trans_status = #{status}
AND (b.book_name LIKE CONCAT('%',#{keyword},'%') OR b.isbn LIKE CONCAT('%',#{keyword},'%'))
ORDER BY t.create_time DESC LIMIT #{offset}, #{pageSize}

SELECT COUNT(*) FROM t_transaction t LEFT JOIN t_textbook b ON t.textbook_id = b.id
AND t.trans_status = #{status}
AND (b.book_name LIKE CONCAT('%',#{keyword},'%') OR b.isbn LIKE CONCAT('%',#{keyword},'%'))

SELECT COUNT(*) FROM t_transaction
WHERE textbook_id = #{bookId}
  AND requester_id = #{requesterId}
  AND trans_status IN (1, 2)
